bool Oauth2Scopes::validJsonOfField(size_t index,
                                    const std::string &fieldName,
                                    const Json::Value &pJson,
                                    std::string &err,
                                    bool isForCreation)
{
    switch(index)
    {
        case 0:
            if(pJson.isNull())
            {
                err="The " + fieldName + " column cannot be null";
                return false;
            }
            if(isForCreation)
            {
                err="The automatic primary key cannot be set";
                return false;
            }
            if(!pJson.isInt())
            {
                err="Type error in the "+fieldName+" field";
                return false;
            }
            break;
        case 1:
            if(pJson.isNull())
            {
                err="The " + fieldName + " column cannot be null";
                return false;
            }
            if(!pJson.isString())
            {
                err="Type error in the "+fieldName+" field";
                return false;
            }
            if(pJson.isString() && drogon::utils::utf8Length(pJson.asCString()) > 100)
            {
                err="String length exceeds limit for the " +
                    fieldName +
                    " field (the maximum value is 100)";
                return false;
            }
            break;
        case 2:
            if(pJson.isNull())
            {
                return true;
            }
            if(!pJson.isString())
            {
                err="Type error in the "+fieldName+" field";
                return false;
            }
            break;
        case 3:
            if(pJson.isNull())
            {
                return true;
            }
            if(!pJson.isString())
            {
                err="Type error in the "+fieldName+" field";
                return false;
            }
            if(pJson.isString() && drogon::utils::utf8Length(pJson.asCString()) > 50)
            {
                err="String length exceeds limit for the " +
                    fieldName +
                    " field (the maximum value is 50)";
                return false;
            }
            break;
        case 4:
            if(pJson.isNull())
            {
                return true;
            }
            if(!pJson.isBool())
            {
                err="Type error in the "+fieldName+" field";
                return false;
            }
            break;
        case 5:
            if(pJson.isNull())
            {
                return true;
            }
            if(!pJson.isBool())
            {
                err="Type error in the "+fieldName+" field";
                return false;
            }
            break;
        default:
            err="Internal error in the server";
            return false;
    }
    return true;
}
std::vector<std::pair<Oauth2Clients,Oauth2ClientScopes>> Oauth2Scopes::getClient(const DbClientPtr &clientPtr) const {
    static const std::string sql = "select * from oauth2_clients,oauth2_client_scopes where oauth2_client_scopes.scope_name = $1 and oauth2_client_scopes.client_id = oauth2_clients.client_id";
    Result r(nullptr);
    {
        auto binder = *clientPtr << sql;
        binder << *name_ << Mode::Blocking >>
            [&r](const Result &result) { r = result; };
        binder.exec();
    }
    std::vector<std::pair<Oauth2Clients,Oauth2ClientScopes>> ret;
    ret.reserve(r.size());
    for (auto const &row : r)
    {
        ret.emplace_back(std::pair<Oauth2Clients,Oauth2ClientScopes>(
            Oauth2Clients(row),Oauth2ClientScopes(row,Oauth2Clients::getColumnNumber())));
    }
    return ret;
}

void Oauth2Scopes::getClient(const DbClientPtr &clientPtr,
                             const std::function<void(std::vector<std::pair<Oauth2Clients,Oauth2ClientScopes>>)> &rcb,
                             const ExceptionCallback &ecb) const
{
    static const std::string sql = "select * from oauth2_clients,oauth2_client_scopes where oauth2_client_scopes.scope_name = $1 and oauth2_client_scopes.client_id = oauth2_clients.client_id";
    *clientPtr << sql
               << *name_
               >> [rcb = std::move(rcb)](const Result &r){
                   std::vector<std::pair<Oauth2Clients,Oauth2ClientScopes>> ret;
                   ret.reserve(r.size());
                   for (auto const &row : r)
                   {
                       ret.emplace_back(std::pair<Oauth2Clients,Oauth2ClientScopes>(
                           Oauth2Clients(row),Oauth2ClientScopes(row,Oauth2Clients::getColumnNumber())));
                   }
                   rcb(ret);
               }
               >> ecb;
}
